+
+/** A condition accepted by the conditional option helpers. */
+export type OptionCondition =
+  | string
+  | OptionDependency;
+
+function normalizeOptionCondition(condition: OptionCondition): OptionDependency {
+  return typeof condition === "string" ? { option: condition } : condition;
+}
+
+function conditionalOptionArgs<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+  required?: boolean,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = (Array.isArray(flagSpec) ? flagSpec : [flagSpec]) as OptionName[];
+  const dependsOn = { ...normalizeOptionCondition(condition), ...(required == null ? {} : { required }) };
+  return valueParser == null
+    ? option(...names, { dependsOn })
+    : option(...names, valueParser, { dependsOn });
+}
+
+/** Creates an option that is required when its dependency is not satisfied. */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionArgs(condition, flagSpec, valueParser, true);
+}
+
+/** Creates an option that is hidden while its dependency is unsatisfied. */
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionArgs(condition, flagSpec, valueParser, false);
+}
+
+/** Creates an option with conditional dependency metadata. */
+export function conditionalOption<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return conditionalOptionArgs(condition, flagSpec, valueParser);
+}
