+    if (term.type === "optional" || term.type === "multiple") {
+      const dependency = findDependency(term.terms);
+      if (dependency) return dependency;
+    }
+  }
+  return undefined;
+}
+
+function optionNamesForUsage(usage: Usage): readonly string[] {
+  const names: string[] = [];
+  for (const term of usage) {
+    if (term.type === "option") names.push(...term.names);
+    else if (term.type === "optional" || term.type === "multiple") {
+      names.push(...optionNamesForUsage(term.terms));
+    }
+  }
+  return names;
+}
+
+function optionStateValue(state: unknown): unknown {
+  if (Array.isArray(state)) return state.length === 1 ? optionStateValue(state[0]) : undefined;
+  if (isDependencySourceState(state)) return optionStateValue(state.result);
+  if (state != null && typeof state === "object" && "success" in state) {
+    const result = state as { readonly success: boolean; readonly value?: unknown };
+    return result.success ? result.value : undefined;
