+}
+
+function isDependencySatisfied(
+  dependency: OptionDependency,
+  states: Readonly<Record<string | symbol, unknown>>,
+  keysByName: ReadonlyMap<string, string | symbol>,
+): boolean {
+  const compound = dependency as { readonly anyOf?: readonly OptionDependencyCondition[]; readonly allOf?: readonly OptionDependencyCondition[] };
+  if ("option" in dependency) return dependencySatisfied(dependency, states, keysByName);
+  const allOf = compound.allOf ?? [];
+  const anyOf = compound.anyOf;
+  return allOf.every((condition) => dependencySatisfied(condition, states, keysByName)) &&
