+import { object } from "@optique/core/constructs";
+import {
+  conditionalOption,
+  option,
+  optionalWhen,
+  requiredWhen,
+} from "@optique/core/primitives";
+import { parseSync } from "@optique/core/parser";
+import { choice, string } from "@optique/core/valueparser";
+import assert from "node:assert/strict";
+import { describe, it } from "node:test";
+
+describe("conditional option dependencies", () => {
+  it("resolves object keys and CLI names", () => {
+    const parser = object({
+      mode: option("--mode", choice(["dev", "prod"] as const)),
+      config: conditionalOption(
+        { option: "--mode", value: "prod" },
+        "--config",
+        string(),
+      ),
+    });
+
+    assert.deepEqual(parseSync(parser, ["--mode", "prod", "--config", "a"]), {
+      mode: "prod",
+      config: "a",
+    });
+    assert.deepEqual(parseSync(parser, ["--mode", "dev"]), {
+      mode: "dev",
+      config: undefined,
+    });
+  });
+
+  it("supports compound conditions and empty groups", () => {
+    const parser = object({
+      a: option("--a"),
+      b: option("--b"),
+      all: conditionalOption({ allOf: [] }, "--all"),
+      any: conditionalOption({ anyOf: [] }, "--any"),
+      either: conditionalOption({ anyOf: [{ option: "a" }, { option: "b" }] }, "--either"),
+    });
+    assert.deepEqual(parseSync(parser, ["--all", "--a", "--either"]), {
+      a: true,
+      b: false,
+      all: true,
+      any: undefined,
+      either: true,
+    });
+  });
+
+  it("reports a required unsatisfied dependency with its flag and value", () => {
+    const parser = object({
+      mode: option("--mode", choice(["dev", "prod"] as const)),
+      output: requiredWhen({ option: "mode", value: "prod" }, "--output", string()),
+    });
+    assert.throws(
+      () => parseSync(parser, ["--mode", "dev"]),
+      /requires option.*--mode.*prod/,
+    );
+  });
+
+  it("hides optional dependencies from documentation and suggestions", () => {
+    const parser = object({
+      enabled: option("--enabled"),
+      detail: optionalWhen("enabled", "--detail", string()),
+    });
+    const suggestions = [...parser.suggest({
+      buffer: [], state: parser.initialState, optionsTerminated: false, usage: parser.usage,
+    }, "")].map((suggestion) => suggestion.value);
+    assert.ok(!suggestions.includes("--detail"));
+  });
+});
